INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6, 0, "", 0, "vo_minigame_1013", 21, "", "", "vo_minigame_1013_top_talk_6_002", 6015, "");
